// ── ADR-094: Toast Notifications ───────────────────────────────────

/// Overlay toast notification.
#[derive(Clone)]
struct Toast {
    message: String,
    color: egui::Color32,
    created: std::time::Instant,
    duration: std::time::Duration,
    dismissable: bool,
    dismissed: bool,
}

impl Toast {
    fn is_expired(&self) -> bool {
        self.dismissed || self.created.elapsed() > self.duration
    }
}

