const BVOL_HIGH: egui::Color32 = egui::Color32::from_rgb(0, 255, 0);           // clrGreen — churn (high vol, low move)
const BVOL_LOW: egui::Color32 = egui::Color32::from_rgb(255, 255, 0);          // clrYellow — low volume
const BVOL_CHURN: egui::Color32 = egui::Color32::from_rgb(255, 0, 255);        // clrMagenta — climax + churn
const BVOL_NORMAL: egui::Color32 = egui::Color32::from_rgb(70, 130, 180);      // clrSteelBlue — normal volume

/// Right margin: empty bars of space after the last candle (MT5 "chart shift" feature).
const CHART_RIGHT_MARGIN: usize = 5;

/// Indicator visibility flags passed to draw_chart.
struct IndicatorFlags {
    sma200: bool,
    sma100: bool,
    kama: bool,
    ema21: bool,
    bollinger: bool,
    ichimoku: bool,
    wma: bool,
    hma: bool,
    psar: bool,
    atr_proj: bool,
    prev_levels: bool,
    pivots: bool,
    fractals: bool,
    harmonics: bool,
    auto_fib: bool,
    supply_demand: bool,
    ehlers_ss: bool,
    ehlers_decycler: bool,
    ehlers_itl: bool,
    ehlers_mama: bool,
    sessions: bool,
    vol_heatmap: bool,
    vwap: bool,
    price_histogram: bool,
    supertrend: bool,
    donchian: bool,
    keltner: bool,
    regression: bool,
    fvg: bool,
    order_blocks: bool,
}

/// All state for one chart viewport.
struct ChartState {
    /// The symbol string shown in the toolbar.
    symbol: String,
    /// Currently selected timeframe.
    timeframe: Timeframe,
    /// Chart rendering style.
    chart_type: ChartType,
    /// Logarithmic price scale (vs linear).
    log_scale: bool,
    // ── Configurable indicator periods ─────────────────────────────────
    sma_slow_period: u32,
    sma_fast_period: u32,
    ema_period: u32,
    rsi_period: u32,
    atr_period: u32,
    bb_period: u32,
    macd_fast: u32,
    macd_slow: u32,
    macd_signal_p: u32,
    stoch_period: u32,
    adx_period: u32,
    fisher_period: u32,
    momentum_period: u32,
    // ── Compare symbol overlay ─────────────────────────────────────────
    compare_symbol: Option<String>,
    compare_bars: Vec<Bar>,
    /// Live bid/ask from streaming quotes (for spread line rendering).
    live_bid: f64,
    live_ask: f64,
    // Extended hours candle (pre/post market)
    ext_open: f64,
    ext_high: f64,
    ext_low: f64,
    ext_close: f64,
    ext_active: bool, // true when ext hours data is available
    /// Raw bar data loaded from cache.
    bars: Vec<Bar>,
    /// Pre-computed SMA(200) — indexed parallel to `bars`.
    sma200: Vec<Option<f64>>,
    /// Pre-computed SMA(100) — indexed parallel to `bars`.
    sma100: Vec<Option<f64>>,
    /// Pre-computed KAMA(10,2,30) — indexed parallel to `bars`.
    kama: Vec<Option<f64>>,
    /// Pre-computed EMA(21).
    ema21: Vec<Option<f64>>,
    /// Bollinger Bands (middle, upper, lower).
    bb_mid: Vec<Option<f64>>,
    bb_upper: Vec<Option<f64>>,
    bb_lower: Vec<Option<f64>>,
    /// RSI(14) — 0..100 range.
    rsi: Vec<Option<f64>>,
    /// Fisher Transform.
    fisher: Vec<Option<f64>>,
    fisher_signal: Vec<Option<f64>>,
    /// ATR(14).
    atr: Vec<Option<f64>>,
    /// MACD(12,26,9).
    macd_line: Vec<Option<f64>>,
    macd_signal: Vec<Option<f64>>,
    macd_hist: Vec<Option<f64>>,
    /// Stochastic(14,3,3).
    stoch_k: Vec<Option<f64>>,
    stoch_d: Vec<Option<f64>>,
    /// ADX(14) + DI+/DI-.
    adx: Vec<Option<f64>>,
    di_plus: Vec<Option<f64>>,
    di_minus: Vec<Option<f64>>,
    /// Ichimoku(9,26,52).
    ichi_tenkan: Vec<Option<f64>>,
    ichi_kijun: Vec<Option<f64>>,
    ichi_span_a: Vec<Option<f64>>,
    ichi_span_b: Vec<Option<f64>>,
    /// Previous candle levels (daily high/low).
    prev_daily_high: Option<f64>,
    prev_daily_low: Option<f64>,
    prev_weekly_high: Option<f64>,
    prev_weekly_low: Option<f64>,
    prev_h4_high: Option<f64>,
    prev_h4_low: Option<f64>,
    prev_h1_high: Option<f64>,
    prev_h1_low: Option<f64>,
    prev_monthly_high: Option<f64>,
    prev_monthly_low: Option<f64>,
    /// WMA(20), HMA(20).
    wma: Vec<Option<f64>>,
    hma: Vec<Option<f64>>,
    /// CCI(20), Williams %R(14).
    cci: Vec<Option<f64>>,
    williams_r: Vec<Option<f64>>,
    /// OBV.
    obv: Vec<Option<f64>>,
    /// Momentum(10).
    momentum: Vec<Option<f64>>,
    /// Parabolic SAR(0.02, 0.2).
    psar: Vec<Option<f64>>,
    /// MTF SMA lines — (label, color_idx, projected_points) matching MTF_MA.mqh.
    /// H1/200, H4/200, D1/200, W1/200, W1/100, MN1/100
    mtf_sma: Vec<(String, Vec<(usize, f64)>)>,
    /// ATR Projection (open ± ATR bands — legacy per-bar, kept for GPU path).
    atr_proj_upper: Vec<Option<f64>>,
    atr_proj_lower: Vec<Option<f64>>,
    /// ATR Projection MTF levels (label, open, atr_value, start_bar_idx) — matches ATR_Projection.mqh.
    atr_proj_levels: Vec<(&'static str, f64, f64, usize)>,
    /// Better Volume classification.
    better_vol_type: Vec<u8>, // 0=normal, 1=climax_up, 2=climax_dn, 3=high, 4=low, 5=churn
    /// Pivot points (computed from daily data).
    pivot_p: Option<f64>,
    pivot_r1: Option<f64>,
    pivot_r2: Option<f64>,
    pivot_s1: Option<f64>,
    pivot_s2: Option<f64>,
    /// Bill Williams Fractals (up/down arrows).
    fractal_up: Vec<bool>,
    fractal_down: Vec<bool>,
    // ── Ehlers indicators ──────────────────────────────────────────────
    /// Super Smoother (overlay).
    ehlers_ss: Vec<Option<f64>>,
    /// Decycler (overlay).
    ehlers_decycler: Vec<Option<f64>>,
    /// Instantaneous Trendline (overlay).
    ehlers_itl: Vec<Option<f64>>,
    /// MAMA (overlay).
    ehlers_mama: Vec<Option<f64>>,
    /// FAMA (overlay).
    ehlers_fama: Vec<Option<f64>>,
    /// Even Better Sinewave (sub-pane, -1 to 1).
    ehlers_ebsw: Vec<Option<f64>>,
    /// Cyber Cycle (sub-pane).
    ehlers_cyber: Vec<Option<f64>>,
    /// CG Oscillator (sub-pane).
    ehlers_cg: Vec<Option<f64>>,
    /// Roofing Filter (sub-pane).
    ehlers_roof: Vec<Option<f64>>,
    /// Supply/demand zones: (bar_idx, zone_high, zone_low, status).
    /// Status: 0=untested, 1=tested (price returned), 2=proven (price bounced)
    supply_zones: Vec<(usize, f64, f64, u8)>,
    /// Earliest timestamp from primary data source (MT5/Alpaca). Bars before this are backfill.
    primary_first_ts: i64,
    /// Timestamps of bars sourced from gap-fill (CryptoCompare/Kraken). Colored magenta.
    gap_fill_timestamps: std::collections::HashSet<i64>,
    demand_zones: Vec<(usize, f64, f64, u8)>,
    /// Auto Fibonacci levels: (price, label, is_extension).
    auto_fib_levels: Vec<(f64, String, bool)>,
    /// Auto Fibonacci swing: (swing_high_price, swing_low_price, swing_high_idx, swing_low_idx).
    auto_fib_swing: Option<(f64, f64, usize, usize)>,
    /// VWAP (volume-weighted average price), anchored daily.
    vwap: Vec<Option<f64>>,
    /// VWAP upper deviation bands (1σ, 2σ, 3σ).
    vwap_upper1: Vec<Option<f64>>,
    vwap_upper2: Vec<Option<f64>>,
    vwap_upper3: Vec<Option<f64>>,
    /// VWAP lower deviation bands (1σ, 2σ, 3σ).
    vwap_lower1: Vec<Option<f64>>,
    vwap_lower2: Vec<Option<f64>>,
    vwap_lower3: Vec<Option<f64>>,
    /// Supertrend line (ATR-based trend bands, single line that flips).
    supertrend: Vec<Option<f64>>,
    /// Supertrend direction: true = bullish (below price), false = bearish (above).
    supertrend_bull: Vec<bool>,
    /// Donchian Channel upper (highest high over N bars).
    donchian_upper: Vec<Option<f64>>,
    /// Donchian Channel lower (lowest low over N bars).
    donchian_lower: Vec<Option<f64>>,
    /// Keltner Channel middle (EMA).
    keltner_mid: Vec<Option<f64>>,
    /// Keltner Channel upper (EMA + ATR×mult).
    keltner_upper: Vec<Option<f64>>,
    /// Keltner Channel lower (EMA - ATR×mult).
    keltner_lower: Vec<Option<f64>>,
    /// Regression Channel middle (regression line).
    regression_mid: Vec<Option<f64>>,
    /// Regression Channel upper (regression + 2σ).
    regression_upper: Vec<Option<f64>>,
    /// Regression Channel lower (regression - 2σ).
    regression_lower: Vec<Option<f64>>,
    /// Squeeze Momentum: momentum histogram value.
    squeeze_mom: Vec<Option<f64>>,
    /// Squeeze state: true = in squeeze (BB inside KC).
    squeeze_on: Vec<bool>,
    /// Pre-computed 20-bar rolling average volume (for volume heatmap candle coloring).
    vol_avg_20: Vec<f64>,
    /// MultiKAMA: KAMA values from higher timeframes projected onto this chart's x-axis.
    /// Each entry: (timeframe_label, Vec of (bar_index_in_this_chart, kama_value))
    multi_kama: Vec<(String, Vec<(usize, f64)>)>,
    /// Detected harmonic patterns.
    harmonics: Vec<HarmonicPattern>,
    /// Drawing annotations.
    drawings: Vec<Drawing>,
    /// Per-drawing style: (line_width, line_style). Indexed parallel to `drawings`.
    drawing_styles: Vec<(f32, LineStyle)>,
    /// Undo stack for drawings (Ctrl+Z pops from drawings into here, Ctrl+Shift+Z restores)
    drawings_undo: Vec<Drawing>,
    selected_drawing: Option<usize>,
    /// Index of the control point being dragged (for resize). None = whole-drawing drag.
    dragging_cp: Option<usize>,
    /// True while dragging a selected drawing (suppresses chart pan).
    is_drawing_drag: bool,
    /// Cached trade overlay (rebuilt when bg data changes, not every frame).
    cached_trade_overlay: TradeOverlay,
    cached_trade_overlay_frame: u64,

    // ── view state ────────────────────────────────────────────────────────
    /// How many bars are visible horizontally (zoom level).
    visible_bars: usize,
    /// Index of the right-most visible bar (0 = oldest, len-1 = newest).
    view_offset: usize,
    /// When replay mode is active, cap visible_range end at this bar index.
    replay_bar_cap: Option<usize>,
    /// Fractional price offset for vertical pan.
    price_pan: f64,
    /// Multiplier applied to the natural price range for vertical zoom.
    price_zoom: f64,

    // ── interaction helpers ───────────────────────────────────────────────
    is_dragging: bool,
    drag_start: Option<egui::Pos2>,
    drag_start_offset: usize,
    drag_start_ppan: f64,
    /// True when dragging on the price axis (TradingView-style vertical scale).
    is_scaling_price: bool,
    /// Price zoom at start of price-axis drag.
    scale_start_zoom: f64,
    /// Y position at start of price-axis drag.
    scale_start_y: f32,
}

