                                let _ = msg_tx.send(BrokerMsg::Connected(format!(
                                    "tastytrade {} — account {} (token: {}...)",
                                    if sandbox { "Sandbox" } else { "Production" },
                                    acct,
                                    &session.session_token[..session.session_token.len().min(8)]
                                )));
