        assert_eq!(mid.len(), 30);
        // After warmup, upper > mid > lower
        for i in 19..30 {
            if let (Some(u), Some(m), Some(l)) = (upper[i], mid[i], lower[i]) {
                assert!(u > m, "Upper {} should be > mid {}", u, m);
                assert!(m > l, "Mid {} should be > lower {}", m, l);
            }
        }
